import java.util.ArrayList;
import java.util.List;

public List<String> splitMessage(String message, int limit) {
    int n = message.length();
    int a = (limit - 3) * (n / (limit - 3)) - n;
    int b = n / (limit - 3);
    if ((n + b + a) % (limit - 2) != 0) 
        return new ArrayList<>();
    int num_parts = (n + b + a) / (limit - 2);
    List<String> result = new ArrayList<>();
    for (int i = 0, k = 1, cnt = 0; i < n || k <= num_parts;) {
        StringBuilder temp = new StringBuilder();
        while (cnt < limit - 3) {
            cnt++;
            temp.append(message.charAt(i++));
            if (i == n) break;
        }
        cnt = 0;
        temp.append(k).append("/").append(num_parts).append(" ");
        k++;
        result.add(temp.toString());
    }
    return result;
}
